  ('South Carolina LIFE Scholarship', 'South Carolina Commission on Higher Education', '5000', '2026-08-01', 'Open to South Carolina residents attending a four-year eligible SC college full-time; requires 3.0 GPA in high school, minimum SAT/ACT score, and class rank; renewable each year with continued academic performance requirements', 'https://www.che.sc.gov/', false, true, 'South Carolina, State-Specific, Merit'),
  ('Maine State Grant Program', 'Finance Authority of Maine', '1500', '2026-05-01', 'Open to Maine residents enrolled at least half-time in degree programs at eligible Maine postsecondary institutions; based on demonstrated financial need as determined by FAFSA; priority given to students who file FAFSA by May 1 each year', 'https://www.famemaine.com/education_loans/scholarships-and-grants/maine-state-grant/', false, false, 'Maine, State-Specific, Financial Need'),
  ('National Garden Clubs Scholarship', 'National Garden Clubs', '4000', '2026-02-28', 'Open to full-time sophomore, junior, senior, or graduate students pursuing degrees in horticulture, botany, landscape design, environmental studies, conservation, or related fields; based on academic achievement and career plans in gardening or environmental fields', 'https://www.gardenclub.org/scholarships', true, false, 'Horticulture, Botany, Environment, Gardening, Conservation'),
  ('National Groundwater Association Scholarship', 'National Groundwater Association', '5000', '2026-01-15', 'Open to undergraduate or graduate students pursuing groundwater-related fields including hydrogeology, hydrology, environmental sciences, or civil engineering with a groundwater focus; based on academic merit and professional career goals', 'https://www.ngwa.org/resources-and-publications/ngwa-foundation/scholarships-and-grants/', true, false, 'Groundwater, Hydrology, Environmental Science, Engineering'),
  ('American Geological Institute Scholarship', 'American Geological Institute Foundation', '10000', '2026-03-15', 'Open to US citizens enrolled full-time in accredited geology, geoscience, or related degree programs; multiple scholarships based on academic achievement, research experience, and commitment to careers in the geosciences', 'https://www.americangeosciences.org/workforce/scholarships', true, false, 'Geology, Earth Science, STEM, Research'),
